UPDATE user_credit_account SET balance=balance-#{amount},updated_at=NOW()
WHERE tenant_id=#{tenantId} AND user_id=#{userId}
RETURNING balance+#{amount} AS balance_before,balance AS balance_after

SELECT  FROM billing_settlement WHERE status='RECONCILIATION_PENDING'
AND tenant_id=#{tenantId}
ORDER BY created_at ASC,id ASC LIMIT #{limit} OFFSET #{offset}
